const item = $input.first().json;
const body = item.body || {};
const ref = (typeof body.actionRef === 'string') ? body.actionRef : '';
function out(o){ return [{ json: o }]; }

const required = ['actionRef','agentId','skillId','client','email','actionType','missionId'];
for (const k of required) {
  if (typeof body[k] !== 'string' || body[k].length === 0) {
    return out({ decision:'error', httpCode:400, response:{ ok:false, actionRef: ref || null, status:'validation_error', message:'Missing or invalid field: ' + k, result:null, deduped:false } });
  }
}
if (body.agentId !== 'hermes' || body.skillId !== 'task.create') {
  return out({ decision:'error', httpCode:400, response:{ ok:false, actionRef: ref, status:'validation_error', message:'Unsupported route ' + body.agentId + '/' + body.skillId + '. Only hermes/task.create is enabled.', result:null, deduped:false } });
}
if (body.data && body.data.simulate === 'transient') {
  return out({ decision:'error', httpCode:503, response:{ ok:false, actionRef: ref, status:'transient_error', message:'Simulated transient downstream error (retryable).', result:null, deduped:false } });
}
const result = { wouldExecute:true, agentId:body.agentId, skillId:body.skillId, actionType:body.actionType, client:body.client, dryRun:true, note:'DRY-RUN: action WOULD have executed. No email, no external mutation.' };
return out({
  decision:'pass',
  actionRef: ref,
  httpCode:200,
  response_ok:{ ok:true, actionRef:ref, status:'ok', message:'DRY-RUN success: action accepted and recorded (not executed).', result, deduped:false },
  response_deduped:{ ok:true, actionRef:ref, status:'deduped', message:'actionRef already processed; not executed again.', result, deduped:true }
});
